sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    var ga = new GlideAjax('DynamicDropdownAPI');

    ga.addParam('sysparm_name', 'getChildValues');
    ga.addParam('sysparm_parent_value', newValue);

    ga.getXMLAnswer(function(response) {

        var states = JSON.parse(response);

        g_form.clearOptions('state');

        //g_form.addOption('state', '', '-- None --');

        for (var i = 0; i < states.length; i++) {
            g_form.addOption('state', states[i], states[i]);
        }
    });
}
